    await updateProcess.run();
    await getOrderProcesses.run();
    showAlert('製程已儲存', 'success');
  },
  updateProcess: async () => {
    await updateProcess.run();
    await getOrderProcesses.run();
  },
  deleteProcess: async () => {
    if (!confirm('確定刪除此製程？')) return;
    await deleteProcess.run();
    await getOrderProcesses.run();
  },
  printQR: async () => {
    await markQRPrinted.run();
    navigateTo('QR_Print',
      {
        material_id: Tbl_order_materials.selectedRow.id,
        order_no: sel_order.selectedOptionLabel,
        part_name: Tbl_order_materials.selectedRow.part_name
      },
      'NEW_WINDOW'
    );
    showAlert('QR Code列印中...', 'success');
  }
}

